SELECT baseline."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh__baseline", sum(upgrade."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh__upgrade", sum((coalesce(baseline."out.electricity.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.electricity.total.energy_consumption..kwh", 0)) * baseline.weight) AS "electricity.total.energy_consumption..kwh__savings", sum(baseline."out.natural_gas.total.energy_consumption..kwh" * baseline.weight) AS "natural_gas.total.energy_consumption..kwh__baseline", sum(upgrade."out.natural_gas.total.energy_consumption..kwh" * baseline.weight) AS "natural_gas.total.energy_consumption..kwh__upgrade", sum((coalesce(baseline."out.natural_gas.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.natural_gas.total.energy_consumption..kwh", 0)) * baseline.weight) AS "natural_gas.total.energy_consumption..kwh__savings" FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND baseline."in.nhgis_tract_gisjoin" = upgrade."in.nhgis_tract_gisjoin" AND baseline.state = upgrade.state AND upgrade.upgrade = 1 AND upgrade.applicability = true WHERE baseline.applicability = true AND baseline.state IN ('CO', 'NM') AND (baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state) IN (SELECT upgrade.bldg_id, upgrade."in.nhgis_tract_gisjoin", upgrade.state FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade WHERE upgrade.upgrade IN (1, 2) AND upgrade.applicability = true GROUP BY upgrade.bldg_id, upgrade."in.nhgis_tract_gisjoin", upgrade.state HAVING count(distinct(upgrade.upgrade)) = 2) GROUP BY 1 ORDER BY 1